out=[f"# {title}\n","## فهرست مطالب\n"]
out.append("\n".join(f"{fa(i)}. [{h}](#{slug(h)})  " for i,(h,_) in enumerate(sections,1))+"\n")
for h,b in sections:
    out.append(f"## {h}\n"); out.append(b+"\n")
out.append("## منابع\n")
rl=[f"[{fa(n)}] {refs[n][0]}"+(f" [{refs[n][2]}]({refs[n][1]})" if refs[n][1] else "")+"  " for n in sorted(refs)]
out.append("\n".join(rl)+"\n")
md=re.sub(r'\n{3,}','\n\n',"\n".join(out))
open(path,"w",encoding="utf-8").write(md)
de=str.maketrans("۰۱۲۳۴۵۶۷۸۹","0123456789")
used=set(int(x.translate(de)) for x in re.findall(r'\[([۰-۹]+)\](?!\()', "\n".join(b for _,b in sections)))
print("sections:",len(sections),"| empty anchors:",md.count("](#)"),"| refs used:",sorted(used),"| listed:",sorted(refs),"| match:",used==set(refs))
